SELECT count(*) FROM char_name, cast_info, role_type, name, title, movie_keyword, kind_type, keyword, movie_companies WHERE cast_info.person_role_id = char_name.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id AND cast_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND movie_keyword.keyword_id = keyword.id AND movie_companies.movie_id = title.id;